// Template code to read from std::cin and write to std::cout
#include <iostream>
#include <vector>

using namespace std;

void solve(vector<int>& nums) {
    bool swapped; 
    do {
        swapped = false; 

        for(int i = 0; i < nums.size() - 1; i++) {
            if (nums[i] > nums[i + 1]) {
                swap(nums[i], nums[i + 1]);
                swapped = true;
            }
        }
    } while (swapped);
}

int main() {
    int n;
    cin >> n;
    cin.ignore();
    nums.resize(n);
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }
    solve(nums);
    for (int i = 0; i < n; i++) {
        cout << nums[i] << " ";
    }
    cout << endl;
    return 0;
}
